query getAllLocations($location: String, $lat: Float!, $lng: Float!, $radius: Float, $limit: Int, $offset: Int, $related: [QueryArgument], $orderBy: String, $widthLg: Int!, $heightLg: Int!, $widthSm: Int!, $heightSm: Int!, $widthLq: Int!, $heightLq: Int!) {
  totalLocations: entryCount(
    section: "locations"
    relatedTo: $related
    locationMap: {unit: Miles, location: $location, country: "US", radius: $radius, coordinate: {lat: $lat, lng: $lng}}
  )
  filteredLocations: entries(
    section: "locations"
    limit: $limit
    offset: $offset
    relatedTo: $related
    locationMap: {unit: Miles, location: $location, country: "US", radius: $radius, coordinate: {lat: $lat, lng: $lng}}
    orderBy: $orderBy
  ) {
    id
    title
    url
    slug
    ... on location_Entry {
      map: locationMap {
        lat
        lng
        distance
        address
        parts {
          number
          address
          city
          state
          postcode
        }
      }
      customLocation @markdown
      locationEligibility {
        eligibility
      }
      foodDistributionLink
      foodDistributionFacebookLink
      foodDistributionPhoneNumber
      foodDistributionInterval
      foodDistributionDateTimes(orderBy: "date asc") {
        ... on foodDistributionDateTimesBlock_Entry {
          date @formatDateTime(format: "M j")
          startTime @formatDateTime(format: "g:ia")
          endTime @formatDateTime(format: "g:ia")
        }
      }
      customFoodDistributionTimes @markdown
      programs {
        id
        title
        slug
        url
      }
      additionalPrograms {
        programTitle
      }
      featuredImage {
        id
        title
        ... on generalUploads_Asset {
          accessibilityText
          mimeType
        }
        imageUrlLgWebp: url @transform(mode: "crop", width: $widthLg, height: $heightLg, format: "webp")
        imageUrlLg: url @transform(mode: "crop", width: $widthLg, height: $heightLg)
        imageUrlSmWebp: url @transform(mode: "crop", width: $widthSm, height: $heightSm, format: "webp")
        imageUrlSm: url @transform(mode: "crop", width: $widthSm, height: $heightSm)
        imageUrlLq: url @transform(mode: "crop", width: $widthLq, height: $heightLq)
      }
    }
  }
}
